import { useCallback, useEffect, useMemo, useState } from 'react';
import { deskCalloutClass } from '@components/deskCalloutStyles';
import { ncShadcnTableClass } from '@components/ncTableStyles';
import { SegmentedControl } from '@components/SegmentedControl';
import { Button } from '@components/ui/button';
import { Input } from '@components/ui/input';
import { Label } from '@components/ui/label';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@components/ui/table';
import { oeFetch } from '@core/oeFetch';
import type {
  PaymentHistoryFilter,
  PaymentHistoryRow,
  PaymentHistorySummary,
  PaymentsListData,
  ReceiptReprintPayload,
} from './chartDepthTypes';
import { ReprintReceiptModal } from './ReprintReceiptModal';
import { formatChartMoney } from './chartDepthUtils';

interface PaymentsPaneProps {
  ajaxUrl: string;
  csrfToken: string;
  pid: number;
  visitId?: number;
}

function typeLabel(type: PaymentHistoryRow['type']): string {
  if (type === 'charge') return 'Charge';
  if (type === 'adjustment') return 'Adjustment';
  return 'Payment';
}

function SummaryCard({
  summary,
}: {
  summary: PaymentHistorySummary;
}) {
  const last = summary.last_receipt;

  return (
    <div className="border rounded p-3 mb-3 bg-[var(--oe-nc-bg-tint)]" id="nc-payments-summary">
      <div className="grid grid-cols-12 gap-3 text-sm">
        <div className="col-span-12 sm:col-span-4">
          <strong>Charges</strong>
          <div>{formatChartMoney(summary.charges_amount)}</div>
        </div>
        <div className="col-span-12 sm:col-span-4">
          <strong>Paid</strong>
          <div>{formatChartMoney(summary.paid_amount)}</div>
        </div>
        <div className="col-span-12 sm:col-span-4">
          <strong>Balance</strong>
          <div>{formatChartMoney(summary.balance_amount)}</div>
        </div>
      </div>
      {last?.receipt_number && (
        <div className="text-sm text-[var(--oe-nc-text-muted)] mt-2">
          Receipt #{last.receipt_number}
          {last.at_label ? ` · ${last.at_label}` : ''}
          {last.cashier ? ` · ${last.cashier}` : ''}
        </div>
      )}
    </div>
  );
}

export function PaymentsPane({ ajaxUrl, csrfToken, pid, visitId }: PaymentsPaneProps) {
  const initialFilter: PaymentHistoryFilter =
    visitId && visitId > 0 ? 'this_visit' : 'all_visits';

  const [filter, setFilter] = useState<PaymentHistoryFilter>(initialFilter);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [rows, setRows] = useState<PaymentHistoryRow[]>([]);
  const [summary, setSummary] = useState<PaymentHistorySummary | null>(null);
  const [hasMore, setHasMore] = useState(false);
  const [offset, setOffset] = useState(0);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [addCorrectionUrl, setAddCorrectionUrl] = useState<string | null>(null);
  const [addCorrectionLabel, setAddCorrectionLabel] = useState('Add correction');
  const [reprintOpen, setReprintOpen] = useState(false);
  const [reprintPayload, setReprintPayload] = useState<ReceiptReprintPayload | null>(null);
  const [reprintSubmitting, setReprintSubmitting] = useState(false);

  const fetchOptions = useMemo(() => ({ ajaxUrl, csrfToken }), [ajaxUrl, csrfToken]);
  const showFilter = !!(visitId && visitId > 0);

  const filterSegments = useMemo(() => {
    const segments = [];
    if (showFilter) {
      segments.push({ id: 'this_visit', label: 'This visit' });
      segments.push({ id: 'all_visits', label: 'All visits' });
    }
    segments.push({ id: 'date_range', label: 'Date range' });
    return segments;
  }, [showFilter]);

  const buildParams = useCallback(
    (pageOffset: number): Record<string, string | number> => {
      const params: Record<string, string | number> = {
        pid,
        offset: pageOffset,
        filter,
      };
      if (filter === 'this_visit' && visitId && visitId > 0) {
        params.visit_id = visitId;
      }
      if (filter === 'date_range') {
        if (dateFrom) params.date_from = dateFrom;
        if (dateTo) params.date_to = dateTo;
      }
      return params;
    },
    [dateFrom, dateTo, filter, pid, visitId],
  );

  const applyListData = useCallback((data: PaymentsListData, append: boolean) => {
    setRows((prev) => (append ? [...prev, ...(data.rows ?? [])] : (data.rows ?? [])));
    setSummary(data.summary ?? null);
    setHasMore(!!data.has_more);
    setOffset(data.next_offset ?? ((data.offset ?? 0) + (data.rows ?? []).length));
    setAddCorrectionUrl(data.add_correction_visible ? (data.add_correction_url ?? null) : null);
    setAddCorrectionLabel(data.add_correction_label ?? 'Add correction');
    if (data.date_from) setDateFrom(data.date_from);
    if (data.date_to) setDateTo(data.date_to);
  }, []);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const data = await oeFetch<PaymentsListData>('chart_depth.payments_list', {
          ...fetchOptions,
          params: buildParams(0),
        });
        if (!cancelled) applyListData(data, false);
      } catch (err) {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : 'Could not load payment history.');
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [applyListData, buildParams, fetchOptions]);

  const loadMore = async () => {
    setLoadingMore(true);
    try {
      const data = await oeFetch<PaymentsListData>('chart_depth.payments_list', {
        ...fetchOptions,
        params: buildParams(offset),
      });
      applyListData(data, true);
    } finally {
      setLoadingMore(false);
    }
  };

  const handleReprint = async (row: PaymentHistoryRow) => {
    if (!row.receipt_id) return;
    setReprintSubmitting(true);
    try {
      const payload = await oeFetch<ReceiptReprintPayload>('chart_depth.receipt_reprint', {
        ...fetchOptions,
        method: 'POST',
        json: { pid, receipt_id: row.receipt_id },
      });
      setReprintPayload(payload);
      setReprintOpen(true);
    } catch (err) {
      window.alert(err instanceof Error ? err.message : 'Could not reprint receipt');
    } finally {
      setReprintSubmitting(false);
    }
  };

  if (loading) {
    return <em>Loading payments…</em>;
  }

  if (error) {
    return <div className={deskCalloutClass('error')}>{error}</div>;
  }

  return (
    <>
      <SegmentedControl
        segments={filterSegments}
        value={filter}
        onChange={(id) => setFilter(id as PaymentHistoryFilter)}
        ariaLabel="Payment filter"
        className="mb-3"
      />

      {filter === 'date_range' && (
        <div className="grid grid-cols-12 gap-3 items-end mb-3">
          <div className="col-auto">
            <Label className="normal-case font-normal mb-1" htmlFor="nc-payments-date-from">From</Label>
            <Input
              type="date"
              className="h-8"
              id="nc-payments-date-from"
              value={dateFrom}
              onChange={(e) => setDateFrom(e.target.value)}
            />
          </div>
          <div className="col-auto">
            <Label className="normal-case font-normal mb-1" htmlFor="nc-payments-date-to">To</Label>
            <Input
              type="date"
              className="h-8"
              id="nc-payments-date-to"
              value={dateTo}
              onChange={(e) => setDateTo(e.target.value)}
            />
          </div>
        </div>
      )}

      {filter === 'this_visit' && summary && (
        <SummaryCard summary={summary} />
      )}

      {addCorrectionUrl && (
        <div className="mb-3">
          <Button variant="outline" size="sm" asChild>
            <a href={addCorrectionUrl} target="_top">
              {addCorrectionLabel}
            </a>
          </Button>
        </div>
      )}

      {!rows.length ? (
        <p className="text-[var(--oe-nc-text-muted)] mb-0">No payment or charge history for this view.</p>
      ) : (
        <div className="overflow-x-auto">
          <Table className={ncShadcnTableClass({ className: 'mb-0' })}>
            <TableHeader>
              <TableRow>
                <TableHead>When</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Description</TableHead>
                <TableHead>Amount</TableHead>
                <TableHead>Visit</TableHead>
                <TableHead />
              </TableRow>
            </TableHeader>
            <TableBody id="nc-payments-rows">
              {rows.map((row, idx) => {
                const visitLabel = row.queue_number
                  ? `#${row.queue_number}${row.visit_date ? ` · ${row.visit_date}` : ''}`
                  : '—';

                return (
                  <TableRow key={`${row.type ?? 'row'}-${row.receipt_id ?? row.occurred_at ?? idx}`}>
                    <TableCell>{row.occurred_at_label ?? row.paid_at_label ?? '—'}</TableCell>
                    <TableCell>{typeLabel(row.type)}</TableCell>
                    <TableCell>
                      <strong>{row.label ?? row.receipt_number ?? '—'}</strong>
                      {row.cashier && (
                        <div className="text-[var(--oe-nc-text-muted)] text-sm">{row.cashier}</div>
                      )}
                    </TableCell>
                    <TableCell>{formatChartMoney(row.amount ?? row.amount_paid)}</TableCell>
                    <TableCell>{visitLabel}</TableCell>
                    <TableCell className="text-right">
                      {row.can_reprint && (
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          disabled={reprintSubmitting}
                          onClick={() => { void handleReprint(row); }}
                        >
                          Reprint
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </div>
      )}

      {hasMore && (
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="mt-2"
          disabled={loadingMore}
          onClick={() => { void loadMore(); }}
        >
          Load more
        </Button>
      )}

      <ReprintReceiptModal
        open={reprintOpen}
        payload={reprintPayload}
        onClose={() => {
          setReprintOpen(false);
          setReprintPayload(null);
        }}
      />
    </>
  );
}
